/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * This is a stub implementation that stores sent webhooks in memory.
 * A production implementation would use a real HTTP client (fetch, axios, etc.)
 * but the interface remains the same.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentWebhook {
  url: string;
  payload: WebhookRequestBody;
  sentAt: Date;
  notificationId: string;
}

export interface WebhookRequestBody {
  notificationId: string;
  type: string;
  subject: string;
  body: string;
  priority: string;
  createdAt: string;
  metadata?: Record<string, unknown>;
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private sentWebhooks: SentWebhook[] = [];

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const url = payload.recipient;
    this.logger.info(`Sending webhook to ${url}: ${payload.subject}`);

    const requestBody: WebhookRequestBody = {
      notificationId: payload.id,
      type: payload.type,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      createdAt: payload.createdAt.toISOString(),
      metadata: payload.metadata,
    };

    const sentAt = new Date();

    this.sentWebhooks.push({
      url,
      payload: requestBody,
      sentAt,
      notificationId: payload.id,
    });

    return {
      success: true,
      notificationId: payload.id,
      channel: this.channel,
      deliveredAt: sentAt,
    };
  }

  /**
   * Get all sent webhooks. Useful for testing.
   */
  getSentWebhooks(): SentWebhook[] {
    return [...this.sentWebhooks];
  }

  /**
   * Clear sent webhooks. Useful for testing.
   */
  clearSentWebhooks(): void {
    this.sentWebhooks = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter();
  });

  function createPayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
    return {
      id: 'notif-0001',
      type: 'order_confirmation',
      channel: 'webhook',
      recipient: 'https://example.com/webhook',
      subject: 'Order Confirmation: order-1',
      body: 'Your order has been placed.',
      priority: 'normal',
      createdAt: new Date('2026-01-01T00:00:00Z'),
      ...overrides,
    };
  }

  it('should have channel set to webhook', () => {
    expect(adapter.channel).toBe('webhook');
  });

  it('should send a webhook and return success', async () => {
    const payload = createPayload();
    const result = await adapter.send(payload);

    expect(result.success).toBe(true);
    expect(result.notificationId).toBe('notif-0001');
    expect(result.channel).toBe('webhook');
    expect(result.deliveredAt).toBeInstanceOf(Date);
  });

  it('should store sent webhook with correct URL', async () => {
    const payload = createPayload({ recipient: 'https://hooks.example.com/notify' });
    await adapter.send(payload);

    const sent = adapter.getSentWebhooks();
    expect(sent).toHaveLength(1);
    expect(sent[0]?.url).toBe('https://hooks.example.com/notify');
  });

  it('should format payload as JSON with expected fields', async () => {
    const payload = createPayload({
      metadata: { userId: 'user-1', orderId: 'order-1' },
    });
    await adapter.send(payload);

    const sent = adapter.getSentWebhooks();
    const body = sent[0]?.payload;
    expect(body?.notificationId).toBe('notif-0001');
    expect(body?.type).toBe('order_confirmation');
    expect(body?.subject).toBe('Order Confirmation: order-1');
    expect(body?.body).toBe('Your order has been placed.');
    expect(body?.priority).toBe('normal');
    expect(body?.createdAt).toBe('2026-01-01T00:00:00.000Z');
    expect(body?.metadata).toEqual({ userId: 'user-1', orderId: 'order-1' });
  });

  it('should handle payload without metadata', async () => {
    const payload = createPayload();
    delete payload.metadata;
    await adapter.send(payload);

    const sent = adapter.getSentWebhooks();
    expect(sent[0]?.payload.metadata).toBeUndefined();
  });

  it('should store multiple sent webhooks', async () => {
    await adapter.send(createPayload({ id: 'notif-0001' }));
    await adapter.send(createPayload({ id: 'notif-0002', recipient: 'https://other.example.com/hook' }));

    const sent = adapter.getSentWebhooks();
    expect(sent).toHaveLength(2);
    expect(sent[0]?.notificationId).toBe('notif-0001');
    expect(sent[1]?.notificationId).toBe('notif-0002');
    expect(sent[1]?.url).toBe('https://other.example.com/hook');
  });

  it('should clear sent webhooks', async () => {
    await adapter.send(createPayload());
    expect(adapter.getSentWebhooks()).toHaveLength(1);

    adapter.clearSentWebhooks();
    expect(adapter.getSentWebhooks()).toHaveLength(0);
  });

  it('should return a defensive copy from getSentWebhooks', async () => {
    await adapter.send(createPayload());
    const first = adapter.getSentWebhooks();
    const second = adapter.getSentWebhooks();
    expect(first).not.toBe(second);
    expect(first).toEqual(second);
  });

  describe('integration with NotificationService', () => {
    it('should work when registered with NotificationService', async () => {
      // Import dynamically to avoid circular dependency issues in test
      const { EventBus } = await import('../../src/events/event-bus.js');
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );

      resetNotificationIdCounter();
      const eventBus = new EventBus();
      const service = new NotificationService(eventBus);
      service.registerAdapter(adapter);

      const result = await service.send({
        id: 'notif-0001',
        type: 'order_confirmation',
        channel: 'webhook',
        recipient: 'https://example.com/webhook',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        priority: 'normal',
        createdAt: new Date(),
      });

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');
      expect(adapter.getSentWebhooks()).toHaveLength(1);
    });
  });
});
